import { html, customElement } from '@umbraco-cms/backoffice/external/lit';
import { UmbModalBaseElement } from '@umbraco-cms/backoffice/modal';
import type { UmbFolderModel} from '@umbraco-cms/backoffice/tree';
import { UMB_ACTION_EVENT_CONTEXT } from '@umbraco-cms/backoffice/action';
import { UmbRequestReloadChildrenOfEntityEvent } from '@umbraco-cms/backoffice/entity-action';
import { FormsFormFolderDetailRepository } from '../../../repository/detail/index.js';
import { FORMS_FORM_FOLDER_ENTITY_TYPE, FORMS_FORM_ROOT_ENTITY_TYPE } from '../../../entities.js';
import type { FormsFolderDeleteConfirmModalData } from './index.js';

@customElement('forms-folder-delete-confirm-modal')
export class FormsFolderDeleteConfirmModalElement extends UmbModalBaseElement<FormsFolderDeleteConfirmModalData> {

	#folderToDelete?: UmbFolderModel | null;
	#folderIsEmpty?: boolean | null;

	#folderDetailRepository = new FormsFormFolderDetailRepository(this);

	async connectedCallback() {
		super.connectedCallback();

		if (!this.data?.unique) return;

		const folderToDeleteResponse = await this.#folderDetailRepository.requestByUnique(this.data.unique);
		this.#folderToDelete = folderToDeleteResponse.data;

		const folderIsEmptyResponse = await this.#folderDetailRepository.isEmpty(this.data.unique);
		this.#folderIsEmpty = folderIsEmptyResponse.data;

		this.requestUpdate();
	}

	async #deleteFolder(event: PointerEvent) {
		event.stopPropagation();

		if (this.data?.unique && this.#folderToDelete) {
			await this.#folderDetailRepository.delete(this.data.unique);

			// TODO: Review this - parentUnique isn't defined on UmbFolderModel but we do have it in the data.
			const reloadEvent = new UmbRequestReloadChildrenOfEntityEvent({
				entityType: this.#folderToDelete["parentUnique"] ? FORMS_FORM_FOLDER_ENTITY_TYPE : FORMS_FORM_ROOT_ENTITY_TYPE,
				unique: this.#folderToDelete["parentUnique"],
			});

			const eventContext = await this.getContext(UMB_ACTION_EVENT_CONTEXT);
			eventContext.dispatchEvent(reloadEvent);
		}

		this._submitModal();
	}

	render() {
		return html`
			<umb-body-layout headline=${this.localize.term("formDelete_folderDeleteModalHeadline")}>
				<uui-box>
					<p>${(this.#folderIsEmpty
						? html`${this.localize.term("formDelete_folderDeleteModalHeadline", this.#folderToDelete?.name)}`
						: html`${this.localize.term("formDelete_folderNotEmptyMessage")}`)}</p>
				</uui-box>
				<uui-button slot="actions" id="cancel" label=${this.localize.term("general_cancel")} @click="${this._rejectModal}">${this.localize.term("general_cancel")}</uui-button>
				${(this.#folderIsEmpty
					? html`<uui-button slot="actions" type="button" label=${this.localize.term("general_delete")} look="primary" color="danger" @click=${this.#deleteFolder}></uui-button>`
					: html``)}
			</umb-body-layout>
		`;
	}
}

export default FormsFolderDeleteConfirmModalElement;

declare global {
	interface HTMLElementTagNameMap {
		'forms-folder-delete-confirm-modal': FormsFolderDeleteConfirmModalElement;
	}
}
